UPDATE inventory_current
SET
    available_qty = CASE
        WHEN #{eventType} = 'PICK_NORMAL' THEN available_qty + #{quantityChange}
        WHEN #{eventType} = 'PICK_DAMAGED_TEMP' THEN available_qty + #{quantityChange}
        WHEN #{eventType} = 'REVERT_DAMAGED' THEN available_qty + #{quantityChange}
        ELSE available_qty
    END,
    damaged_temp_qty = CASE
        WHEN #{eventType} = 'PICK_DAMAGED_TEMP' THEN damaged_temp_qty - #{quantityChange}
        WHEN #{eventType} = 'REVERT_DAMAGED' THEN damaged_temp_qty - #{quantityChange}
        ELSE damaged_temp_qty
    END,
    last_event_id = #{eventId},
    last_event_type = #{eventType},
    updated_by = #{updatedBy}
WHERE product_id = #{productId}
  AND location_id = #{locationId}
  AND (last_event_id IS NULL OR last_event_id < #{eventId})
